        "content": "// components/dynamicHome/f2ab68d7d8446ac0e372a886a3dcd79589def7a00c3ca538468e6bd68496ce7f/homePage-CLIENT-XXXXX.js\nclass CustomHomePage extends HTMLElement {\n  constructor() {\n    super();\n    this.attachShadow({ mode: 'open' });\n  }\n\n  connectedCallback() {\n    this.render();\n    this.loadInventory();\n  }\n\n  async loadInventory() {\n    const grid = this.shadowRoot.getElementById('productGrid');\n    grid.innerHTML = 'Loading exclusive racing gear...';\n\n    try {\n      const res = await fetch('/api/inventory');\n      const inventory = await res.json();\n\n      // Filter high-demand racing ski gear\n      const racingGear = inventory.filter(item => item.name.includes('Racing') || item.sku.includes('RC'));\n\n      grid.innerHTML = racingGear\n        .map(\n          (item) => `\n                <div class=\"card exclusive-offer\">\n                    <h3>${item.name}</h3>\n                    <p class=\"stock limited-stock\">${\n                      item.stock > 0\n                        ? 'Limited Stock: ' + item.stock\n                        : 'Out of Stock'\n                    }</p>\n                    <p class=\"price premium-price\">$${(item.cost * 1.2).toFixed(2)}</p>\n                    <button \n                        class=\"buy-btn exclusive-btn\" \n                        data-id=\"${item.id}\"\n                        ${item.stock <= 0 ? 'disabled' : ''}>\n                        ${item.stock > 0 ? 'Buy Now - Exclusive Offer' : 'Sold Out'}\n                    </button>\n                    <p class=\"exclusive-message\">Exclusive offer for valued clients like you!</p>\n                </div>\n            `\n        )\n        .join('');\n\n      this.shadowRoot.querySelectorAll('.buy-btn').forEach((btn) => {\n        btn.addEventListener('click', (e) => {\n          const itemId = e.target.dataset.id;\n          const item = racingGear.find((i) => i.id === itemId);\n          this.dispatchEvent(\n            new CustomEvent('navigate-order', {\n              detail: { item: item },\n              bubbles: true,\n              composed: true,\n            })\n          );\n        });\n      });\n    } catch (e) {\n      grid.innerHTML = '<p>Error loading exclusive inventory.</p>';\n    }\n  }\n\n  render() {\n    this.shadowRoot.innerHTML = `\n        <style>\n            :host { display: block; animation: fadeIn 0.3s; }\n            .grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(250px, 1fr)); gap: 20px; }\n            .card { background: white; padding: 20px; border-radius: 8px; box-shadow: 0 2px 5px rgba(0,0,0,0.1); text-align: center; font-family: 'Segoe UI', sans-serif; }\n            .exclusive-offer { border: 2px solid #e74c3c; }\n            .limited-stock { color: #e74c3c; font-weight: bold; }\n            .premium-price { font-size: 1.4rem; color: #2c3e50; font-weight: bold; }\n            .exclusive-btn { background: #e74c3c; color: white; }\n            .exclusive-btn:hover { background: #c0392b; }\n            .exclusive-message { font-size: 0.8rem; color: #7f8c8d; margin-top: 10px; }\n            @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n        </style>\n\n        <h2>Exclusive Racing Gear for Your Young Champions</h2>\n        <div id=\"productGrid\" class=\"grid\"></div>\n        `;\n  }\n}\n\ncustomElements.define('home-page', CustomHomePage);",
