        "fileName": "javascript",
        "lang": "javascript",
        "content": "// Update the initApp function in index.html\nasync function initApp() {\n  // ...\n  const HOME_HASH = 'f2ab68d7d8446ac0e372a886a3dcd79589def7a00c3ca538468e6bd68496ce7f'; // Update this line\n  const ORDER_HASH = urlParams.get('orderHash') || 'legacy';\n\n  await registerComponent(\n    'home-page',\n    BaseHomePage,\n    'homePage',\n    HOME_HASH\n  );\n  // ...\n}",
