        "content": "// index.html\nconst urlParams = new URLSearchParams(window.location.search);\nconst HOME_HASH = urlParams.get('homeHash') || 'legacy';\nif (state.clientProfile && state.clientProfile.id === 'CLIENT-00001') {\n  urlParams.set('homeHash', 'f2ab68d7d8446ac0e372a886a3dcd79589def7a00c3ca538468e6bd68496ce7f');\n}",
