        "content": "// components/dynamicHome/f2ab68d7d8446ac0e372a886a3dcd79589def7a00c3ca538468e6bd68496ce7f/homePage-CLIENT-00001.js\nclass CustomHomePage extends HTMLElement {\n  constructor() {\n    super();\n    this.attachShadow({ mode: 'open' });\n  }\n\n  connectedCallback() {\n    this.render();\n    this.loadInventory();\n  }\n\n  async loadInventory() {\n    const grid = this.shadowRoot.getElementById('productGrid');\n    grid.innerHTML = 'Loading exclusive inventory...';\n\n    try {\n      const res = await fetch('/api/inventory');\n      const inventory = await res.json();\n\n      // Filter high-demand racing ski gear\n      const racingSkis = inventory.filter(item => item.name.includes('Racing'));\n\n      grid.innerHTML = racingSkis\n        .map(\n          (item) => `\n                <div class=\"card exclusive\">\n                    <h3>${item.name}</h3>\n                    <p class=\"stock limited\">${\n                      item.stock > 0\n                        ? 'Limited Stock: ' + item.stock\n                        : 'Out of Stock'\n                    }</p>\n                    <p class=\"price premium\">$${(item.cost * 1.2).toFixed(2)}</p>\n                    <button \n                        class=\"buy-btn exclusive-btn\" \n                        data-id=\"${item.id}\"\n                        ${item.stock <= 0 ? 'disabled' : ''}>\n                        ${item.stock > 0 ? 'Buy Now' : 'Sold Out'}\n                    </button>\n                </div>\n            `\n        )\n        .join('');\n\n      this.shadowRoot.querySelectorAll('.buy-btn').forEach((btn) => {\n        btn.addEventListener('click', (e) => {\n          const itemId = e.target.dataset.id;\n          const item = racingSkis.find((i) => i.id === itemId);\n          this.dispatchEvent(\n            new CustomEvent('navigate-order', {\n              detail: { item: item },\n              bubbles: true,\n              composed: true,\n            })\n          );\n        });\n      });\n    } catch (e) {\n      grid.innerHTML = '<p>Error loading inventory.</p>';\n    }\n  }\n\n  render() {\n    this.shadowRoot.innerHTML = `\n        <style>\n            :host { display: block; animation: fadeIn 0.3s; }\n            .grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(250px, 1fr)); gap: 20px; }\n            .card.exclusive { background: linear-gradient(145deg, #ffffff, #f0f0f0); padding: 20px; border-radius: 8px; box-shadow: 0 2px 5px rgba(0,0,0,0.1); text-align: center; font-family: 'Segoe UI', sans-serif; border: 1px solid #e74c3c; }\n            .card h3 { margin: 0 0 10px 0; color: #2c3e50; }\n            .price.premium { font-size: 1.2rem; color: #e74c3c; font-weight: bold; }\n            .stock.limited { color: #7f8c8d; font-size: 0.9rem; margin-bottom: 15px; }\n            button.exclusive-btn { background: #e74c3c; color: white; border: none; padding: 10px 20px; border-radius: 5px; cursor: pointer; width: 100%; font-size: 1rem; }\n            button.exclusive-btn:hover { background: #c0392b; }\n            button:disabled { background: #ccc; cursor: not-allowed; }\n            @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }\n        </style>\n\n        <h2>Exclusive Racing Skis</h2>\n        <div id=\"productGrid\" class=\"grid\"></div>\n        `;\n  }\n}\n\ncustomElements.define('home-page', CustomHomePage);",
